async (params, browser) => {
  // Search Yelp
  await browser.open(`https://www.yelp.com/search?find_desc=${params.query}&find_loc=${params.location}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'businessName\'], [class*=\'search-result\'], [data-testid=\'serp-ia-card\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-testid="serp-ia-card"], [class*="container"][class*="hoverable"], [class*="businessName"]'); const cards = items.length > 0 ? items : document.querySelectorAll('[class*="search-result"], li[class*="border"]'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const nameEl = el.querySelector('[class*="businessName"] a, h3 a, a[href*="/biz/"]'); const ratingEl = el.querySelector('[class*="star"][aria-label], [class*="rating"], [role="img"][aria-label]'); const reviewCountEl = el.querySelector('[class*="reviewCount"], [class*="review-count"]'); const categoryEl = el.querySelector('[class*="category"] a, [class*="priceCategory"] a'); const priceEl = el.querySelector('[class*="priceRange"], [class*="price-range"]'); const addressEl = el.querySelector('[class*="secondary"] address, [class*="address"], address'); const imgEl = el.querySelector('img[src*="yelp"], img'); const linkEl = el.querySelector('a[href*="/biz/"]'); results.push({ name: nameEl ? nameEl.textContent.trim() : '', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', category: categoryEl ? categoryEl.textContent.trim() : '', price_range: priceEl ? priceEl.textContent.trim() : '', address: addressEl ? addressEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, location: '' + params.location + '', result_count: results.length, results: results }`)

  return search_results
}
